const input = items[0].json;
let rawText = input.output || input.text || input.response || 
              (input.content?.parts?.[0]?.text) || (input.message?.content) || "";

// === PRE-DETECT: khách rớt SĐT / tự giới thiệu tên giữa chat ===
// Mục đích: chặn việc LLM hiểu nhầm sang URGENT_CONSULT khi khách CUNG CẤP
// thông tin của mình. Trường hợp này phải dồn về SALES_LEAD/close_deal để
// chạy nhánh Test Drive Extractor (đã hỗ trợ partial state).
let _chatMsg = '';
let _lastIntent = '';
try { _chatMsg = ($('When chat message received3').first().json.chatInput || '').toString(); } catch(e) {}
try { _lastIntent = ($('parse_session').first().json._prev?.last_intent) || ''; } catch(e) {}

const _cleaned = _chatMsg.replace(/[\s\-\.()]/g, '');
const _hasPhone = /(?:\+?84|0)[0-9]{9,10}/.test(_cleaned);
// Detect khách CÓ Ý cho SĐT nhưng SAI ĐỊNH DẠNG (vd "sđt 09012" — chỉ 5 số sau số 0)
const _phoneIntent = /\b(s[đd]t|s[ốo]\s*[đd]i[ệe]n\s*tho[ạa]i|li[êe]n\s*(h[ệe]|l[ạa]c)\s*(qua|theo|v[ớo]i|b[ằa]ng)|g[ọo]i\s*(em|m[ìi]nh|t[ôo]i|anh|ch[ịi])\s*qua|phone\s*number)/i.test(_chatMsg);
// Phone giống dạng số VN nhưng độ dài SAI (4-8 digit sau prefix 0 hoặc 84)
const _phoneNumberLoose = /(?:\+?84|0)\d{4,8}(?!\d)/.test(_cleaned);
const _phoneFormatInvalid = (_phoneIntent || _phoneNumberLoose) && !_hasPhone;
const _hasSelfIntro = /(?:\b(?:em|anh|ch[ịi]|t[ôo]i|m[ìi]nh)\s+t[êe]n\b|\bt[êe]n\s+(?:em|anh|ch[ịi]|t[ôo]i|m[ìi]nh|l[àa])\b|\b(?:em|m[ìi]nh|t[ôo]i)\s+l[àa]\s+[A-ZÀ-Ỹa-zà-ỹ]+|\bg[ọo]i\s+(?:em|m[ìi]nh)\s+l[àa]\b)/i.test(_chatMsg);
// Chỉ override khi đang trong ngữ cảnh sale-related, tránh đè lên SAFETY_GUARD/COMPLAINT
const _salesCtxIntents = ['SALES_LEAD','SERVICE_APPOINTMENT','NETWORK_LOCATION','BRAND_INFO','URGENT_CONSULT','AMBIGUOUS','GREETING',''];
const _inSalesCtx = _salesCtxIntents.includes(_lastIntent);

// === LEAD CONTINUATION: nếu đã có lead với phone nhưng chưa complete ===
// → các turn tiếp theo (khách trả lời tên xe / showroom / lịch) phải tiếp tục đi vào
//   Test Drive Extractor để bồi field còn thiếu, KHÔNG được route sang consultation/disambiguator.
let _leadHasPhone = false;
let _leadComplete = false;
try {
  const _prev = $('parse_session').first().json._prev || {};
  _leadHasPhone = !!_prev.lead_has_phone;
  _leadComplete = !!_prev.lead_complete;
} catch(e) {}
const _leadInProgress = _leadHasPhone && !_leadComplete;

// === PHÂN BIỆT context của phone drop ===
// Có sales history (đã hỏi xe ở turn trước) → đăng ký lái thử CHỦ ĐỘNG → close_deal hợp lý.
// Cold drop turn đầu (chưa từng hỏi gì về xe) → consultation soft, hỏi xe quan tâm trước.
let _hasSalesHistoryInPast = false;
try {
  const _hist = $('parse_session').first().json._prev?.history || [];
  _hasSalesHistoryInPast = _hist.some(h => (h.intent || '').toUpperCase() === 'SALES_LEAD');
} catch (e) {}
const _hasSalesHistory = _lastIntent === 'SALES_LEAD' || _hasSalesHistoryInPast || _leadInProgress;
const _shouldForceClose = (_hasPhone || _hasSelfIntro) && _hasSalesHistory;
const _phoneColdDrop = (_hasPhone || _hasSelfIntro) && !_hasSalesHistory && _inSalesCtx;
// ⚠️ KHÔNG dùng _leadInProgress để ép close_deal — đã có phone không có nghĩa khách muốn lái thử.
// Tôn trọng phán đoán của LLM (consultation/pricing/tech_specs/close_deal). Chỉ override khi:
//   - Khách RỚT contact mới ở turn này (_hasPhone || _hasSelfIntro) + đang trong sales context.
//   - LLM có thể tự đoán close_deal nếu khách nói lái thử/đặt cọc/mua.
const _shouldForceLead = _shouldForceClose;

try {
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error("Không tìm thấy JSON");
  const p = JSON.parse(jsonMatch[0]);

  // === HANDLE intents[] FORMAT (cả multi và single) ===
  if (p.intents && Array.isArray(p.intents)) {
    if (p.intents.length === 1) {
      // Single intent wrapped in intents[] → unwrap to legacy format
      const single = p.intents[0];
      const shared = p.shared || {};
      // Merge single intent + shared vào p (legacy format)
      Object.keys(single).forEach(k => { p[k] = single[k]; });
      if (!p.brand && shared.brand) p.brand = shared.brand;
      if (!p.model_slug && shared.model_slug) p.model_slug = shared.model_slug;
      p.status = p.status ?? true;
      delete p.intents;
      delete p.shared;
      console.log('[XU_LY_CATEGORY] Unwrapped single intent from intents[] → legacy format:', p.category);
      // Falls through to existing legacy parsing below ↓
    } else if (p.intents.length >= 2) {
    return [{
      json: {
        _multi: true,
        _intents: p.intents,
        _shared: p.shared || {},
        category: 'MULTI',
        sales_subcategory: '',
        brand: (p.shared?.brand || p.intents[0]?.brand || '').toLowerCase(),
        model_slug: (p.shared?.model_slug || p.intents[0]?.model_slug || '').toLowerCase(),
        car_type: '', seat_min: null, fuel: '', budget_max: null,
        price_sort: null, use_case: null, qa_intents: [],
        compare_with_brand: '', compare_with_model: '', compare_target: '',
        status: true,
        _contact_override: false, _has_phone: _hasPhone,
        _has_self_intro: _hasSelfIntro, _lead_in_progress: false,
        _has_sales_history: false, _phone_cold_drop: false,
        _phone_format_invalid: _phoneFormatInvalid
      }
    }];
  } // end intents.length >= 2
  } // end intents[] format handler

  // === OVERRIDE: ép category khi phát hiện contact của khách ===
  let _category = p.category || null;
  let _sub = (p.sales_subcategory || "consultation").toLowerCase().trim();
  let _override = false;
  if (_shouldForceLead) {
    _category = 'SALES_LEAD';
    _sub = 'close_deal';
    _override = true;
  } else if (_phoneColdDrop) {
    // Khách rớt SĐT TURN ĐẦU chưa có context → soft consultation, KHÔNG form-fill rập khuôn.
    _category = 'SALES_LEAD';
    _sub = 'consultation';
    _override = true;
  }

  return [{
    json: {
      category: _category,
      sales_subcategory: _sub,
      brand: (p.brand || "").toLowerCase().trim(),
      model_slug: (p.model_slug || "").toLowerCase().trim(),
      car_type: (p.car_type || "").toLowerCase().trim(),
      seat_min: p.seat_min ? Number(p.seat_min) : null,
      fuel: (p.fuel || "").toLowerCase().trim(),
      budget_max: p.budget_max ? Number(p.budget_max) : null,
      price_sort: (p.price_sort || "").toLowerCase().trim() || null,
      use_case: p.use_case || null,
      qa_intents: Array.isArray(p.qa_intents) ? p.qa_intents : [],
      compare_with_brand: (p.compare_with_brand || "").toLowerCase().trim(),
      compare_with_model: (p.compare_with_model || "").trim(),
      compare_target: (p.compare_target || "").toLowerCase().trim(),
      status: typeof p.status === "boolean" ? p.status : false,
      _contact_override: _override,
      _has_phone: _hasPhone,
      _has_self_intro: _hasSelfIntro,
      _lead_in_progress: _leadInProgress,
      _has_sales_history: _hasSalesHistory,
      _phone_cold_drop: _phoneColdDrop,
      _phone_format_invalid: _phoneFormatInvalid,
      _multi: false
    }
  }];
} catch(e) {
  // Ngay cả khi LLM lỗi format, nếu khách đã rớt contact / đang có lead chưa complete thì vẫn cứu vào lead flow
  if (_shouldForceLead) {
    return [{ json: { category: 'SALES_LEAD', sales_subcategory: 'close_deal', status: true, _contact_override: true, _has_phone: _hasPhone, _has_self_intro: _hasSelfIntro, _lead_in_progress: _leadInProgress, _has_sales_history: _hasSalesHistory, _phone_cold_drop: false, _multi: false, raw_debug: rawText.substring(0,200) }}];
  }
  if (_phoneColdDrop) {
    return [{ json: { category: 'SALES_LEAD', sales_subcategory: 'consultation', status: true, _contact_override: true, _has_phone: _hasPhone, _has_self_intro: _hasSelfIntro, _lead_in_progress: false, _has_sales_history: false, _phone_cold_drop: true, _multi: false, raw_debug: rawText.substring(0,200) }}];
  }
  return [{ json: { category: "ERROR_FORMAT", _multi: false, raw_debug: rawText.substring(0,200), status: false }}];
}

// FILTER ENGINE + MARKDOWN TRIMMER + FAQ INTENT FILTER + COMPARISON + ROLLING PRICE CALC
// Paste vào n8n node: "Code in JavaScript" (sau Switch.SALES_LEAD)
const d = $input.first().json;
const base = 'https://raw.githubusercontent.com/Meeyana/thacoauto-lib/main/';

// === Entity từ Router ===
const brand = (d.brand || "").toLowerCase().trim();
const model_slug = (d.model_slug || "").toLowerCase().trim();
const car_type = (d.car_type || "").toLowerCase().trim();
const seat_min = d.seat_min ? Number(d.seat_min) : null;
const fuel = (d.fuel || "").toLowerCase().trim();
const budget_max = d.budget_max ? Number(d.budget_max) : null;
const price_sort = (d.price_sort || "").toLowerCase().trim();
const qa_intents = Array.isArray(d.qa_intents) ? d.qa_intents : [];

// === Entity so sánh ===
const compare_target = (d.compare_target || "").toLowerCase().trim();
const compare_with_brand = (d.compare_with_brand || "").toLowerCase().trim();
const compare_with_model = (d.compare_with_model || "").trim();

const sales_subcategory = (d.sales_subcategory || "consultation").toLowerCase().trim();

// === Detect intent fine-grained từ chatInput (multi-quote vs compare, summary vs detail) ===
let _chatInput = '';
try { _chatInput = ($('When chat message received3').first().json.chatInput || '').toLowerCase(); } catch(e) {}

const wantsCompare = (Array.isArray(qa_intents) && qa_intents.includes('SO_SANH'))
  || /so sánh|khác (nhau|biệt)|nên (chọn|mua) (xe |cái |bản )?nào|đáng mua hơn|\bvs\b|so với/.test(_chatInput);

const wantsPriceDetail = /chi tiết|breakdown|liệt kê|từng (phí|khoản)|phí (trước bạ|biển|đăng kiểm|bảo hiểm|dịch vụ)|cụ thể (giá|phí)/.test(_chatInput);

// CHỈ tính rolling price khi khách thực sự hỏi "lăn bánh" hoặc hỏi chi tiết phí.
// Mặc định khi khách hỏi "giá" → chỉ trả giá niêm yết.
const wantsRollingPrice = wantsPriceDetail
  || /lăn bánh|ra biển|on[- ]?road|out[- ]the[- ]door|tổng (chi phí|tiền)|đến khi (chạy|đi) được|bao nhiêu (tiền )?(thì|mới) (chạy|đi|ra) được/.test(_chatInput);
const province = (d.province || "ho-chi-minh").toLowerCase().trim();

// === LEAD CAPTURE SCORING — buying-signal weighted ===
// Mỗi turn có trọng số theo "độ gần với quyết định mua".
// Tích lũy 10 turn gần nhất + turn hiện tại → đến ngưỡng → bật should_capture_lead.
// Fallback: salesTurnCount ≥ 4 (cơ chế đếm câu cũ).
// ⚠️ ĐỌC TRỰC TIẾP từ parse_session vì restore_router replaces $input bằng xu_ly_category json (KHÔNG có _prev).
let history = [];
try { history = $('parse_session').first().json._prev?.history || []; } catch (e) { history = []; }

const SCORE_TABLE = {
  // SALES_LEAD sub-categories
  close_deal: 10,
  pricing_finance: 7,
  tech_specs: 6,
  consultation: 5,
  // mode-level (override cho consultation nếu cao hơn)
  compare_internal: 5,
  compare_segment: 3,
  shortlist_small: 2,
  multi_quote: 2,
  compare_external: 2,
  shortlist_big: 1,
  ask_more: 1,
  // category-level non-SALES (fallback theo category)
  URGENT_CONSULT: 8,
  TRADE_IN: 2,
  BRAND_INFO: 1,
  // còn lại = 0 (GREETING/SAFETY/COMPLAINT/OUT_OF_SCOPE/AMBIGUOUS/COMPANY_CONTACT/POLICY_LEGAL/SERVICE_APPOINTMENT/RECRUITMENT)
};
const DEEP_INTENTS = ['AN_TOAN', 'NOI_THAT', 'NGOAI_THAT', 'VAN_HANH'];

function scoreTurn(entry) {
  if (!entry) return 0;
  const cat = (entry.intent || '').toUpperCase();
  const sub = (entry.subcat || '').toLowerCase();
  const md = (entry.mode || '').toLowerCase();
  const qa = Array.isArray(entry.qa_intents) ? entry.qa_intents : [];
  let s = 0;
  if (cat === 'SALES_LEAD') {
    s = SCORE_TABLE[sub] || 0;
    if (SCORE_TABLE[md] !== undefined && SCORE_TABLE[md] > s) s = SCORE_TABLE[md];
  } else if (SCORE_TABLE[cat] !== undefined) {
    s = SCORE_TABLE[cat];
  }
  // Bonus +2 mỗi qa_intents "deep" (research sâu)
  const deepCount = qa.filter(q => DEEP_INTENTS.includes(q)).length;
  s += deepCount * 2;
  return s;
}

// Chỉ tính 10 turn gần nhất để score không phình theo session dài
const recentHistory = history.slice(-10);
const historyScore = recentHistory.reduce((acc, h) => acc + scoreTurn(h), 0);

// Score turn HIỆN TẠI (chưa nằm trong history)
const currentTurnScore = scoreTurn({
  intent: d.category,
  subcat: sales_subcategory,
  mode: null,  // mode chưa tính tại điểm này — sẽ tự được tính sau qua mode routing
  qa_intents: qa_intents
});

const totalScore = historyScore + currentTurnScore;

const SCORE_THRESHOLD = 10;
const TURN_FALLBACK = 4;

const sales_turn_count = recentHistory.filter(h => h.intent === 'SALES_LEAD').length
  + (d.category === 'SALES_LEAD' ? 1 : 0);

// Đã có phone trong test_drives → KHÔNG xin SĐT nữa (tránh hỏi đi hỏi lại)
const _alreadyHavePhone = !!(d._prev && d._prev.lead_has_phone);
// SAI FORMAT phone — khách có ý cho nhưng nhập sai → AI cần hỏi lại
const _phoneFormatInvalid = !!d._phone_format_invalid;
const _thresholdHit = (totalScore >= SCORE_THRESHOLD) || (sales_turn_count >= TURN_FALLBACK);
const should_capture_lead = _thresholdHit && !_alreadyHavePhone;
const lead_threshold_hit = _alreadyHavePhone
  ? `already_have_phone (no need to ask)`
  : (totalScore >= SCORE_THRESHOLD
      ? `score:${totalScore}>=${SCORE_THRESHOLD}`
      : (sales_turn_count >= TURN_FALLBACK ? `turns:${sales_turn_count}>=${TURN_FALLBACK}` : ''));

const THACO_BRANDS = ['kia', 'mazda', 'peugeot', 'bmw', 'mini', 'thaco-truck', 'thaco-bus'];

// =========================================================
// HELPER 1: Trim markdown — chỉ giữ section H2 trong allowlist
// =========================================================
function trimMarkdown(md, allowlist, opts = {}) {
  if (!md || typeof md !== 'string') return '';
  const maxChars = opts.maxChars || 3500;
  md = md.replace(/^---[\s\S]*?---\s*/m, '');
  md = md.replace(/^>.*$/gm, '');
  md = md.replace(/!\[[^\]]*\]\([^\)]*\)/g, '');
  const parts = md.split(/^## /m);
  const intro = parts.shift() || '';
  let kept = intro.trim() + '\n';
  for (const part of parts) {
    const heading = part.split('\n')[0].toLowerCase();
    if (allowlist.some(k => heading.includes(k.toLowerCase()))) {
      kept += '\n## ' + part.trim() + '\n';
    }
  }
  if (kept.length > maxChars) kept = kept.slice(0, maxChars) + '\n...[đã rút gọn]';
  return kept.trim();
}

// =========================================================
// HELPER 1B: Extract chỉ Tóm tắt + Trang bị nổi bật phiên bản đầu (cho compare)
// =========================================================
function extractCompareMd(md) {
  if (!md || typeof md !== 'string') return '';
  md = md.replace(/^---[\s\S]*?---\s*/m, '');
  md = md.replace(/^>.*$/gm, '');
  md = md.replace(/!\[[^\]]*\]\([^\)]*\)/g, '');

  // Split theo ^## để lấy từng section H2 — tránh dùng \Z (không hỗ trợ trong JS regex,
  // bị hiểu là literal Z và với /i flag thành [Zz] → cắt sai ở chữ z trong "mazda")
  const sections = md.split(/^## /m);
  let result = '';

  // 1. Section Tóm tắt
  for (const sec of sections.slice(1)) {
    const heading = sec.split('\n')[0].toLowerCase();
    if (heading.includes('tóm tắt') || heading.includes('tom tat')) {
      result += '## ' + sec.trim() + '\n\n';
      break;
    }
  }

  // 2. Section Trang bị nổi bật → chỉ giữ phiên bản H3 đầu tiên
  for (const sec of sections.slice(1)) {
    const heading = sec.split('\n')[0].toLowerCase();
    if (heading.includes('trang bị nổi bật')) {
      const h3Parts = sec.split(/^### /m);
      if (h3Parts.length >= 2) {
        const header = '## ' + h3Parts[0].trim();
        const firstVersion = h3Parts[1].trim();
        result += `${header}\n\n### ${firstVersion}\n`;
      } else {
        result += '## ' + sec.trim() + '\n';
      }
      break;
    }
  }

  return result.trim();
}

// =========================================================
// HELPER 1C: Tính giá lăn bánh — fetch policy + compute theo seat + brand
// =========================================================
let _rollingPolicy = null;
async function calcRollingPrice(modelPrice, provinceArg, seatArg, brandArg) {
  if (!modelPrice || modelPrice <= 0) return null;
  try {
    if (!_rollingPolicy) {
      const data = await this.helpers.httpRequest({
        method: 'GET',
        url: base + 'wiki/policies/rolling-price.json',
        json: true,
        returnFullResponse: false
      });
      _rollingPolicy = (typeof data === 'string') ? JSON.parse(data) : data;
    }
    const p = _rollingPolicy;

    // 1. Province → phí trước bạ % + phí biển số
    const provinceKey = (p.registration_fee_pct[provinceArg]) ? provinceArg : 'default';
    const reg_pct = p.registration_fee_pct[provinceKey];
    const plate = p.license_plate_fee_vnd[provinceKey];
    const reg_fee = Math.round(modelPrice * reg_pct);

    // 2. Bảo hiểm vật chất theo % giá xe
    const physical_ins = Math.round(modelPrice * p.physical_insurance_pct);

    // 3. TNDS theo SỐ CHỖ NGỒI
    const seatNum = Number(seatArg || 5);
    let tnds;
    let tnds_tier;
    if (seatNum <= 5) {
      tnds = p.tnds_insurance_yr_vnd['5_seat_or_less'];
      tnds_tier = '≤5 chỗ';
    } else if (seatNum <= 7) {
      tnds = p.tnds_insurance_yr_vnd['6_to_7_seat'];
      tnds_tier = '6-7 chỗ';
    } else {
      tnds = p.tnds_insurance_yr_vnd['8_seat_or_more'];
      tnds_tier = '≥8 chỗ';
    }

    // 4. Service fee theo BRAND
    const brandKey = (brandArg || '').toLowerCase().trim();
    const service_fee = p.service_fee_vnd.by_brand[brandKey] || p.service_fee_vnd.default;

    // 5. Phí cố định
    const inspection = p.fixed_fees_vnd.inspection;
    const road_maintenance = p.fixed_fees_vnd.road_maintenance_yr;

    // 6. Tổng
    const total = modelPrice + reg_fee + plate
      + inspection + road_maintenance + tnds + service_fee
      + physical_ins;

    return {
      province_used: provinceKey,
      registration_fee_pct: reg_pct,
      seat_used: seatNum,
      tnds_tier,
      brand_used: brandKey || 'default',
      breakdown: {
        model_price: modelPrice,
        registration_fee: reg_fee,
        license_plate: plate,
        inspection,
        road_maintenance,
        tnds_insurance: tnds,
        service_fee,
        physical_insurance: physical_ins
      },
      total,
      labels: p.fee_labels_vi,
      notes: p.notes
    };
  } catch (e) {
    return { error: e.message };
  }
}

// Format helper VNĐ
function fmtVnd(n) {
  if (n === null || n === undefined) return '—';
  return Math.round(n).toLocaleString('de-DE') + ' ₫';
}

// === SUMMARY format: chỉ giá niêm yết + tổng lăn bánh + tổng phí phụ ===
function formatRollingPriceSummary(modelName, calc, priceMin, priceMax) {
  if (!calc || calc.error) return `\n[LỖI tính giá lăn bánh: ${calc?.error || 'không có giá'}]`;
  const fees = calc.total - calc.breakdown.model_price;
  const provinceText = calc.province_used === 'ho-chi-minh' ? 'HCM' :
    calc.province_used === 'ha-noi' ? 'HN' : 'tỉnh khác';
  const priceRange = priceMin
    ? (priceMax && priceMax !== priceMin ? `${fmtVnd(priceMin)} – ${fmtVnd(priceMax)}` : fmtVnd(priceMin))
    : '—';
  return `\n\n=== GIÁ TÓM TẮT ${modelName} (đăng ký ${provinceText}, ${calc.seat_used} chỗ) ===
- Giá niêm yết: ${priceRange}
- 🚗 LĂN BÁNH ƯỚC TÍNH (bản thấp nhất): ${fmtVnd(calc.total)}
- Phí phụ trợ ước tính (gộp chung — trước bạ + biển + bảo hiểm + đăng kiểm + dịch vụ): ~${fmtVnd(fees)}

[Mode SUMMARY — KHÔNG được dump từng dòng phí. Cuối câu mời khách: "Anh/Chị muốn em báo CHI TIẾT từng khoản phí không ạ?"]`;
}

// Format calc result thành text bundle (DETAIL — full breakdown)
function formatRollingPriceBundle(modelName, calc) {
  if (!calc || calc.error) return `\n[LỖI tính giá lăn bánh: ${calc?.error || 'không có giá'}]`;
  const b = calc.breakdown;
  const L = calc.labels;
