// Helper: lookup giá trị qua synonym map → trả canonical key, hoặc null
function lookupSynonym(value, dict) {
  if (!value) return null;
  const v = value.toString().toLowerCase().trim();
  if (!dict || !dict.synonyms) return null;

  // 1. Direct match canonical key
  for (const canon of Object.keys(dict.synonyms)) {
    if (canon.toLowerCase() === v) return canon;
  }
  // 2. Match trong list synonym (exact)
  for (const [canon, syns] of Object.entries(dict.synonyms)) {
    if (syns.some(s => s.toLowerCase() === v)) return canon;
  }
  // 3. Partial match (substring) — nới lỏng cho text dài
  for (const [canon, syns] of Object.entries(dict.synonyms)) {
    if (syns.some(s => v.includes(s.toLowerCase()) || s.toLowerCase().includes(v))) return canon;
  }
  return null;
}

// Helper: validate model_slug có trong list không
function validateSlug(slug, validList) {
  if (!slug) return null;
  const s = slug.toString().toLowerCase().trim().replace(/\s+/g, '-');

  // 1. Exact match
  if (validList.includes(s)) return s;

  // 2. Thử ghép brand prefix: "carens" + brand="kia" → "kia-carens"
  if (d.brand) {
    const guess = `${d.brand.toLowerCase()}-${s}`;
    if (validList.includes(guess)) return guess;
  }

  // 3. Partial match có dash boundary: "cx-3" → "mazda-cx-3"
  const candidates = validList.filter(v => {
    if (d.brand && !v.startsWith(d.brand.toLowerCase() + '-')) return false;
    return v.endsWith('-' + s) || v === s || v.includes('-' + s + '-');
  });
  if (candidates.length === 1) return candidates[0];
  if (candidates.length > 1) {
    return candidates.sort((a, b) => a.length - b.length)[0];
  }

  // 4. ⭐ MỚI — Strip-dash compare: "cx3" → "mazdacx3" → so với "mazda-cx-3" → "mazdacx3" ✅
  //    Áp dụng cho TẤT CẢ slug viết liền không dash (cx3, cx30, mx5, k5...)
  const stripDash = (x) => x.replace(/-/g, '');
  const sStripped = stripDash(s);

  const fuzzyCandidates = validList.filter(v => {
    if (d.brand && !v.startsWith(d.brand.toLowerCase() + '-')) return false;
    const vStripped = stripDash(v);
    // EXACT strip match: "cx3" === "mazdacx3"? Không, nhưng endsWith mới đúng
    // endsWith match: "mazdacx3".endsWith("cx3") ✅; "mazdacx30".endsWith("cx3") ❌
    return vStripped === sStripped || vStripped.endsWith(sStripped);
  });

  if (fuzzyCandidates.length === 1) return fuzzyCandidates[0];
  if (fuzzyCandidates.length > 1) {
    // Ưu tiên slug ngắn hơn (cụ thể hơn): "cx3" → "mazda-cx-3" thắng "mazda-cx-30"
    return fuzzyCandidates.sort((a, b) => a.length - b.length)[0];
  }

  return null;
}


// Validate seat_min: phải là số nguyên trong canonical
function validateSeat(value, allowed) {
  if (value === null || value === undefined || value === '') return null;
  const n = Number(value);
  if (!Number.isFinite(n)) return null;
  // Cho phép giá trị nhỏ hơn min canonical (vd khách hỏi "4 chỗ" nhưng catalog chỉ có từ 5)
  // Nhưng giới hạn trong khoảng hợp lý 2-16
  return (n >= 2 && n <= 16) ? n : null;
}

// Normalize tất cả entity
const normalized = {
  brand:      lookupSynonym(d.brand, vocab.brand),
  car_type:   lookupSynonym(d.car_type, vocab.car_type),
  fuel:       lookupSynonym(d.fuel, vocab.fuel),
  use_case:   lookupSynonym(d.use_case, vocab.use_case),
  seat_min:   validateSeat(d.seat_min, vocab.seat?.canonical || []),
  model_slug: validateSlug(d.model_slug, vocab.model_slugs || []),
  compare_target: validateSlug(d.compare_target, vocab.model_slugs || []),
};

// Track giá trị AI bịa (để review & bổ sung synonym sau)
const unknown = {};
for (const [k, originalRaw] of Object.entries({
  brand: d.brand, car_type: d.car_type, fuel: d.fuel,
  use_case: d.use_case, model_slug: d.model_slug
})) {
  if (originalRaw && !normalized[k]) {
    unknown[k] = originalRaw;
  }
}

return [{
  json: {
    ...d,
    ...normalized,
    budget_max: d.budget_max ? Number(d.budget_max) : null,  // numeric, không cần normalize
    _unknown: Object.keys(unknown).length ? unknown : null,
    _normalized_at: new Date().toISOString()
  }
}];

const input = items[0].json;
let rawText = input.output || input.text || input.response ||
              (input.content?.parts?.[0]?.text) || (input.message?.content) || "";

const router = $('xu_ly_category').first().json;

// Fallback: kế thừa brand từ turn gần nhất trong history (nếu turn hiện tại + extractor đều rỗng)
let inheritedBrand = '';
try {
  const hist = $('parse_session').first().json._prev?.history || [];
  for (let i = hist.length - 1; i >= 0; i--) {
    if (hist[i].brand) { inheritedBrand = hist[i].brand; break; }
  }
} catch(e) {}

try {
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error("Không tìm thấy JSON");
  const p = JSON.parse(jsonMatch[0]);
  return [{
    json: {
      category: router.category,
      province: (p.province || "").toLowerCase().trim(),
      showroom_name: (p.showroom_name || "").trim(),
      brand: (p.brand || router.brand || inheritedBrand || "").toLowerCase().trim(),
      brand_inherited_from_history: !p.brand && !router.brand && !!inheritedBrand,
      user_location: (p.user_location || "").trim(),
      status: true
    }
  }];
} catch (e) {
  return [{
    json: {
      category: router.category,
      province: "", showroom_name: "", brand: router.brand || inheritedBrand || "",
      user_location: "",
      status: false,
      _error: e.message,
      _raw_debug: rawText.substring(0, 200)
    }
  }];
}

// DEALER LOOKUP — 6 mode + fallback URL ở mode không có kết quả:
//  1. area_overview          → khách hỏi tên KHU VỰC → liệt kê TẤT CẢ showroom + tổng quan brand
//  2. specific_found         → khách hỏi đích danh 1 showroom → trả info chi tiết
//  3. specific_not_found     → match 0 showroom (kèm fallback URL)
//  4. nearest_by_location    → khách hỏi "gần nhất từ <vị trí>" → haversine sort, top 3
//  5. province_link          → khách hỏi chung theo tỉnh → trả URL
//  6. ask_province           → khách chưa nói gì → hỏi khu vực
const d = $input.first().json;
const base = 'https://raw.githubusercontent.com/Meeyana/thacoauto-lib/main/';
const FALLBACK_URL = 'https://thacoautotphcm.vn/showrooms';
const MAX_DISTANCE_KM = 150; // Ngưỡng coi là 'quá xa' — vượt vùng phủ dữ liệu hiện tại (HCM + lân cận)

const province      = (d.province || "").toLowerCase().trim();
const showroom_name = (d.showroom_name || "").toLowerCase().trim();
const brand         = (d.brand || "").toLowerCase().trim();
const user_location = (d.user_location || "").trim();

let mode = "ask_province";
let bundle = '';
let matched_showrooms = [];
let province_url = null;
let user_coords = null;
let fallback_url = FALLBACK_URL;

const PASSENGER_BRANDS = ['kia', 'mazda', 'peugeot', 'bmw', 'mini'];
function brandMatches(showroom, b) {
  if (!b) return true;
  const slugs = showroom.brand_slugs || [];
  // Exact match — KHÔNG dùng includes() vì 'kia-frontier'.includes('kia') sẽ kéo nhầm xe tải
  if (!slugs.includes(b)) return false;
  // Brand xe du lịch → chỉ lấy showroom oto, loại tai/bus
  if (PASSENGER_BRANDS.includes(b) && showroom.type_showroom && showroom.type_showroom !== 'oto') return false;
  return true;
}


async function fetchCatalog() {
  const cat = await this.helpers.httpRequest({
    method: 'GET',
    url: base + 'wiki/dealers/catalog.json',
    json: true,
    returnFullResponse: false
  });
  return (typeof cat === 'string') ? JSON.parse(cat) : cat;
}

function haversineKm(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const toRad = x => x * Math.PI / 180;
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a = Math.sin(dLat/2)**2 +
            Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLon/2)**2;
  return 2 * R * Math.asin(Math.sqrt(a));
}

async function geocodeUserLocation(addr) {
  const q = /vietnam|việt nam/i.test(addr) ? addr : (addr + ", Việt Nam");
  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://nominatim.openstreetmap.org/search',
      qs: { format: 'json', q, limit: 1 },
      headers: { 'User-Agent': 'thacoauto-chatbot/1.0 (contact: phogotarot@gmail.com)' },
      json: true,
      returnFullResponse: false
    });
    const arr = (typeof res === 'string') ? JSON.parse(res) : res;
    if (Array.isArray(arr) && arr.length) {
      return {
        lat: parseFloat(arr[0].lat),
        lon: parseFloat(arr[0].lon),
        display_name: arr[0].display_name || ""
      };
    }
  } catch (e) {}
  return null;
}

function norm(s) { return (s || "").toLowerCase().trim().replace(/\s+/g, ' '); }
function tokens(s) { return norm(s).split(/[\s\-,]+/).filter(Boolean); }
function scoreMatch(title, query) {
  const t = norm(title);
  const q = norm(query);
  if (!t || !q) return 0;
  if (t === q) return 100;
  const qPattern = new RegExp(`(^|\\s)${q.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}(\\s|$)`);
  if (qPattern.test(t)) return 80;
  const tPattern = new RegExp(`(^|\\s)${t.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}(\\s|$)`);
  if (tPattern.test(q)) return 60;
  const qTok = tokens(q);
  const tTokSet = new Set(tokens(t));
  if (qTok.length && qTok.every(w => tTokSet.has(w))) return 40;
  return 0;
}

try {
  // ============================================
  // 1. SHOWROOM ĐÍCH DANH / KHU VỰC
  // ============================================
  if (showroom_name) {
    const data = await fetchCatalog.call(this);

    const scored = (data.showrooms || [])
      .map(s => ({ s, score: scoreMatch(s.title, showroom_name) }))
      .filter(x => x.score > 0)
      .sort((a, b) => b.score - a.score);

    let matches = [];
    if (scored.length) {
      const bestScore = scored[0].score;
      matches = scored.filter(x => x.score === bestScore).map(x => x.s);
    }

    if (brand && matches.length > 1) {
      const filtered = matches.filter(s => brandMatches(s, brand));
      if (filtered.length) matches = filtered;
    }

    matched_showrooms = matches;

    if (matches.length === 0) {
      mode = "specific_not_found";
      bundle = `[KHÔNG tìm thấy showroom "${d.showroom_name}" trong hệ thống.
URL TRA CỨU TỰ HELP: ${FALLBACK_URL}
Gợi ý cho AI: xin lỗi khách, đính kèm URL tra cứu, đề xuất gọi hotline 1900 545 591.]`;
    } else if (matches.length === 1) {
      mode = "specific_found";
      const f = matches[0];
      bundle = `=== SHOWROOM: ${f.title} ===
- Thương hiệu: ${f.brands.join(', ')}
- 📍 Địa chỉ: ${f.address.full}
- 📞 Bán hàng: ${f.phone_sale || '—'}
- 📞 Dịch vụ: ${f.phone_service || '—'}
- 🏷 Dịch vụ cung cấp: ${f.services.join(', ')}
- 🗺 Maps: ${f.map_url || '—'}
- 🌐 Website: ${f.website || '—'}`;
    } else {
      mode = "area_overview";
      const allBrands = [...new Set(matches.flatMap(s => s.brands || []))].sort();
      const areaName = d.showroom_name;
      const sampleAddr = matches[0].address || {};
      const ward = sampleAddr.ward ? `Phường ${sampleAddr.ward}` : '';
      const city = sampleAddr.province || '';
      bundle = `=== TỔNG QUAN KHU VỰC: ${areaName.toUpperCase()} ===
- Vị trí: ${[ward, city].filter(Boolean).join(', ') || '—'}
- Số showroom trong khu vực: ${matches.length}
- Tất cả thương hiệu có mặt: ${allBrands.join(', ')}

=== CHI TIẾT TỪNG SHOWROOM ===
${matches.map(s => `
**${s.title}**
- Thương hiệu: ${s.brands.join(', ')}
- 📍 ${s.address.full}
- 📞 Bán hàng: ${s.phone_sale || '—'} | Dịch vụ: ${s.phone_service || '—'}
- 🏷 ${s.services.join(', ')}
- 🗺 ${s.map_url || '—'}`).join('\n\n---\n')}`;
    }

  // ============================================
  // 2. NEAREST BY LOCATION
  // ============================================
  } else if (user_location) {
    const data = await fetchCatalog.call(this);

    user_coords = await geocodeUserLocation.call(this, user_location);

    if (!user_coords) {
      mode = "nearest_no_geocode";
      bundle = `[Không xác định được toạ độ cho vị trí "${user_location}".
URL TRA CỨU TỰ HELP: ${FALLBACK_URL}
Gợi ý cho AI: hỏi lại khách quận/phường cụ thể hơn HOẶC gửi URL trên + hotline 1900 545 591 để khách tự tra.]`;
    } else {
      let candidates = (data.showrooms || []).filter(s =>
        typeof s.lat === 'number' && typeof s.lon === 'number'
      );
      if (brand) {
        candidates = candidates.filter(s => brandMatches(s, brand));
      }

      // Tính distance trước, lọc theo threshold rồi mới rank
      const allRanked = candidates
        .map(s => ({ ...s, distance_km: haversineKm(user_coords.lat, user_coords.lon, s.lat, s.lon) }))
        .sort((a, b) => a.distance_km - b.distance_km);

      const nearestKm = allRanked.length ? allRanked[0].distance_km : null;
      const inRange = allRanked.filter(s => s.distance_km <= MAX_DISTANCE_KM);

      if (!candidates.length) {
        mode = "nearest_no_match";
        bundle = `[Không có showroom nào${brand ? ` của thương hiệu ${brand.toUpperCase()}` : ''} có toạ độ trong dữ liệu.
URL TRA CỨU TỰ HELP: ${FALLBACK_URL}
Gợi ý cho AI: xin lỗi khách, gửi URL trên để khách tự tìm + hotline 1900 545 591.]`;
      } else if (!inRange.length) {
        // ⚠ Tất cả showroom đều > MAX_DISTANCE_KM → ngoài vùng phủ
        mode = "nearest_too_far";
        matched_showrooms = [];  // KHÔNG trả showroom xa cho AI để khỏi bị render
        bundle = `[Khu vực "${user_location}" CHƯA NẰM TRONG VÙNG PHỦ DỮ LIỆU. Showroom${brand ? ` ${brand.toUpperCase()}` : ''} gần nhất cũng cách ~${nearestKm.toFixed(0)} km (vượt ngưỡng ${MAX_DISTANCE_KM} km).
LÝ DO: dữ liệu showroom hiện tại của em chỉ đầy đủ cho cụm Hồ Chí Minh và các tỉnh lân cận (Bình Dương, Bà Rịa-Vũng Tàu, Tây Ninh). Các tỉnh xa hơn (Phú Yên, Khánh Hoà, Đà Nẵng, Cần Thơ, miền Bắc...) thư viện chưa cập nhật đầy đủ.
URL TRA CỨU TOÀN QUỐC: ${FALLBACK_URL}
Gợi ý cho AI:
1. Xin lỗi chân thành, nói RÕ "dữ liệu chưa phủ vùng đó".
2. TUYỆT ĐỐI KHÔNG liệt kê showroom 300-400km.
3. Đính kèm URL trên để khách tự tra danh sách showroom toàn quốc.
4. Mời gọi hotline 1900 545 591.]`;
      } else {
        const ranked = inRange.slice(0, 3);
        matched_showrooms = ranked;
        mode = "nearest_by_location";

        const brandLabel = brand ? brand.toUpperCase() : 'tất cả thương hiệu';
        bundle = `=== SHOWROOM ${brandLabel} GẦN NHẤT TỪ "${user_location}" ===
Toạ độ khách: lat=${user_coords.lat.toFixed(5)}, lon=${user_coords.lon.toFixed(5)}
Tham chiếu OSM: ${user_coords.display_name}

Top ${ranked.length} showroom gần nhất (theo đường chim bay):

${ranked.map((s, i) => `
**${i + 1}. ${s.title}** — cách ~${s.distance_km.toFixed(1)} km
- Thương hiệu: ${s.brands.join(', ')}
- 📍 ${s.address.full}
- 📞 Bán hàng: ${s.phone_sale || '—'} | Dịch vụ: ${s.phone_service || '—'}
- 🏷 ${(s.services || []).join(', ')}
- 🗺 ${s.map_url || '—'}`).join('\n\n---\n')}

Lưu ý: khoảng cách là đường chim bay (haversine), thực tế đi đường có thể dài hơn.`;
      }
    }

  // ============================================
  // 3. PROVINCE LINK
  // ============================================
  } else if (province) {
    const data = await fetchCatalog.call(this);
    province_url = (data.province_urls || {})[province] || null;

    if (province_url) {
      mode = "province_link";
      bundle = `=== KHÁCH HỎI CHUNG SHOWROOM TẠI: ${province} ===
URL chính thức: ${province_url}
Brand quan tâm: ${brand || 'tất cả'}`;
    } else {
      mode = "province_no_link";
      bundle = `[Chưa có URL website riêng cho tỉnh "${province}".
URL TRA CỨU TỰ HELP (HCM): ${FALLBACK_URL}
Gợi ý cho AI: gửi URL trên để khách lọc theo tỉnh, kèm hotline 1900 545 591.]`;
    }

  // ============================================
  // 4. ASK PROVINCE
  // ============================================
  } else {
    mode = "ask_province";
    bundle = `[Khách hỏi chung "showroom" nhưng chưa nói khu vực hay tên cụ thể.
Gợi ý cho AI: hỏi lịch sự "Anh/Chị đang ở tỉnh/thành hoặc khu vực nào ạ?"
Có thể đính kèm URL tra cứu để khách tự xem trước: ${FALLBACK_URL}]`;
  }

} catch (e) {
  bundle = `[LỖI: ${e.message}.
URL TRA CỨU TỰ HELP: ${FALLBACK_URL}
Hướng dẫn khách gọi hotline 1900 545 591.]`;
  mode = "error";
}

return [{
  json: {
    ...d,
    mode,
    matched_showrooms,
    matched_count: matched_showrooms.length,
    province_url,
    user_coords,
    fallback_url,
    context_bundle: bundle
  }
}];

