const trigger = $('When chat message received3').first().json;

// === ĐỌC SESSION TỪ D1 ===
const sessionRow = $('d1_read_session').first().json.data;

let prev = {
  history: [],
  last_user_msg: '',
  last_intent: '',
  last_brand: '',
  last_model: '',
  last_ai_reply: '',
  lead_partial: null,
  lead_has_phone: false,
  lead_complete: false
};

if (sessionRow && sessionRow.sessionId) {
  let history = [];
  try {
    history = sessionRow.history_json ? JSON.parse(sessionRow.history_json) : [];
    if (!Array.isArray(history)) history = [];
  } catch(e) { history = []; }

  prev.history = history;
  prev.last_user_msg = sessionRow.last_user_msg || '';
  prev.last_intent   = sessionRow.last_intent   || '';
  prev.last_brand    = sessionRow.last_brand    || '';
  prev.last_model    = sessionRow.last_model    || '';
  prev.last_ai_reply = sessionRow.last_ai_reply || '';
}

// === ĐỌC LEAD STATE TỪ D1 ===
try {
  const tdRow = $('d1_read_test_drive').first().json.data;
  if (tdRow && tdRow.sessionId) {
    const partial = {
      name: tdRow.name || null,
      phone: tdRow.phone || null,
      model_interest: tdRow.model_interest || null,
      showroom: tdRow.showroom || null,
      preferred_datetime: tdRow.preferred_datetime || null
    };
    prev.lead_partial = partial;
    prev.lead_has_phone = !!partial.phone;
    prev.lead_complete = !!(partial.name && partial.phone && partial.model_interest && partial.showroom && partial.preferred_datetime);
  }
} catch(e) {}

return [{ json: { ...trigger, _prev: prev } }];

// abuse_guard — chặn bot/spam TRƯỚC khi gọi AI Agent.
// Đọc _prev.history (đã load ở parse_session) → KHÔNG tốn sheet read thêm.
// Block thì set _abuse=true; downstream IF sẽ dead-end ở silent_reply (output rỗng,
// KHÔNG ghi qa_logs, KHÔNG update sessions, KHÔNG gọi AI = 0 token + 0 sheet write).

const d = $input.first().json;
const trigger = $('When chat message received3').first().json;
const history = (d._prev && d._prev.history) || [];
const now = Date.now();
const userMsg = (trigger.chatInput || '').toString();

let _abuse = false;
let _abuse_reason = '';

// === GUARD 1: BOT BURST — quá nhiều request trong 1 giây ===
// Nếu history có ≥10 entry trong vòng 1000ms gần đây → bot spam (con người không gõ nhanh vậy).
const BOT_WINDOW_MS = 1000;
const BOT_THRESHOLD = 10;
const last1s = history.filter(h => {
  if (!h.ts) return false;
  const t = Date.parse(h.ts);
  return !isNaN(t) && (now - t) < BOT_WINDOW_MS;
}).length;
if (last1s >= BOT_THRESHOLD) {
  _abuse = true;
  _abuse_reason = `bot_burst:${last1s}_req_in_${BOT_WINDOW_MS}ms`;
}

// === GUARD 2: HUMAN SPAM — quá nhiều msg trong 5 phút ===
// ≥25 entry trong 300_000ms (5 min) → human spam.
const SPAM_WINDOW_MS = 300_000;
const SPAM_THRESHOLD = 25;
if (!_abuse) {
  const last5m = history.filter(h => {
    if (!h.ts) return false;
    const t = Date.parse(h.ts);
    return !isNaN(t) && (now - t) < SPAM_WINDOW_MS;
  }).length;
  if (last5m >= SPAM_THRESHOLD) {
    _abuse = true;
    _abuse_reason = `human_spam:${last5m}_msg_in_${SPAM_WINDOW_MS / 1000}s`;
  }
}

// === GUARD 3: MSG RỖNG ===
if (!_abuse && userMsg.trim().length < 1) {
  _abuse = true;
  _abuse_reason = 'empty_msg';
}

if (_abuse) {
  console.log('[ABUSE_GUARD BLOCK]', _abuse_reason, 'sessionId=', trigger.sessionId);
}

return [{ json: { ...d, _abuse, _abuse_reason } }];

// silent_reply — DEAD-END khi abuse_guard flag.
// Trả output rỗng để chatTrigger response im lặng. KHÔNG đi tiếp sang qa_logs / save_sessions
// → tiết kiệm 100% token AI + 0 sheet write.
return [{
  json: {
    output: '',
    _abuse: true,
    _abuse_reason: $input.first().json._abuse_reason || 'unknown'
  }
}];

// keyword_router — SLIM: chỉ giữ 3 chức năng:
// 1. Model slug detection (validate với wiki catalog — TUYỆT ĐỐI không sai)
// 2. Profanity → bắt buộc SAFETY_GUARD
// 3. Entity extraction (brand, car_type, fuel, budget, compare, price_sort)
// KHÔNG còn intent keyword signals — để AI tự phân loại category.

const trigger = $('When chat message received3').first().json;
const chatInput = (trigger.chatInput || '').toString();
const msg = chatInput.toLowerCase().trim();
const d = $input.first().json;

// === FETCH CATALOG — validate slug tồn tại trong thư viện ===
const base = 'https://raw.githubusercontent.com/Meeyana/thacoauto-lib/main/';
let VALID_SLUGS = new Set();
try {
  const raw = await this.helpers.httpRequest({ method: 'GET', url: base + 'wiki/models/catalog.json', json: true, returnFullResponse: false });
  const catalog = (typeof raw === 'string') ? JSON.parse(raw) : raw;
  (catalog.models || []).forEach(m => VALID_SLUGS.add(m.slug));
} catch (e) { /* fetch fail → skip validation */ }

// === MODEL MAP: tên phổ biến → slug ===
const MODEL_MAP = {
  'morning': 'kia-morning', 'new morning': 'kia-morning-all-new',
  'sonet': 'kia-sonet', 'seltos': 'kia-seltos', 'soluto': 'kia-soluto',
  'k3': 'kia-k3', 'k5': 'kia-k5',
  'sportage': 'kia-sportage', 'sorento': 'kia-sorento',
  'sorento hybrid': 'kia-sorento-hybrid',
  'carnival': 'kia-carnival', 'carens': 'kia-carens',
  'new carnival': 'kia-carnival',
  'mazda2': 'mazda-2', 'mazda 2': 'mazda-2',
  'mazda 2 sport': 'mazda-2-sport', 'mazda2 sport': 'mazda-2-sport',
  'mazda3': 'mazda-3', 'mazda 3': 'mazda-3',
  'mazda 3 sport': 'mazda-3-sport', 'mazda3 sport': 'mazda-3-sport',
  'cx-3': 'mazda-cx-3', 'cx3': 'mazda-cx-3', 'cx 3': 'mazda-cx-3',
  'cx-5': 'mazda-cx-5', 'cx5': 'mazda-cx-5', 'cx 5': 'mazda-cx-5',
  'cx-8': 'mazda-cx-8', 'cx8': 'mazda-cx-8', 'cx 8': 'mazda-cx-8',
  'cx-30': 'mazda-cx-30', 'cx30': 'mazda-cx-30', 'cx 30': 'mazda-cx-30',
  'cx-90': 'mazda-cx-90', 'cx90': 'mazda-cx-90', 'cx 90': 'mazda-cx-90',
  'mx-5': 'mazda-mx-5', 'mx5': 'mazda-mx-5',
  '2008': 'peugeot-2008', '3008': 'peugeot-3008',
  '5008': 'peugeot-5008', '408': 'peugeot-408',
  'x3': 'bmw-x3', 'x4': 'bmw-x4', 'x5': 'bmw-x5', 'x6': 'bmw-x6', 'x7': 'bmw-x7',
  'x3 all new': 'bmw-x3-all-new', 'x3 mới': 'bmw-x3-all-new',
  'ix3': 'bmw-ix3', 'z4': 'bmw-z4',
  '3 series': 'bmw-3-series', '4 series': 'bmw-4-series',
  '5 series': 'bmw-5-series', '5 series all new': 'bmw-5-series-all-new',
  '7 series': 'bmw-7-series',
  '320i': 'bmw-3-series', '330i': 'bmw-3-series', '430i': 'bmw-4-series',
  '520i': 'bmw-5-series', '530i': 'bmw-5-series', '730li': 'bmw-7-series',
  'i4': 'bmw-i4', 'i7': 'bmw-i7',
  '520': 'bmw-5-series', '530': 'bmw-5-series',
  '320': 'bmw-3-series', '330': 'bmw-3-series', '430': 'bmw-4-series', '730': 'bmw-7-series',
  'mini 3 door': 'mini-3-door', 'mini 3 cửa': 'mini-3-door',
  'mini 5 door': 'mini-5-door', 'mini 5 cửa': 'mini-5-door',
  'cooper': 'mini-3-door',
  'countryman': 'mini-countryman', 'clubman': 'mini-clubman',
  'mini convertible': 'mini-convertible', 'mini mui trần': 'mini-convertible'
};

// === PATTERN-BASED BRAND INFERENCE ===
const BRAND_PATTERNS = [
  { rx: /\b[cm]x[- ]?(\d+)\b/i, brand: 'mazda', slugFn: (m) => {
    const raw = m[0].toLowerCase().replace(/\s+/g, '-');
    return 'mazda-' + raw.replace(/^(cx|mx)(\d)/, '$1-$2');
  }},
  { rx: /\bbt[- ]?(\d+)\b/i,        brand: 'mazda', slugFn: (m) => 'mazda-bt-' + m[1] },
  { rx: /\bmazda[- ]?(\d+)\b/i,     brand: 'mazda', slugFn: (m) => 'mazda-' + m[1] },
  { rx: /\bx(\d)\b/i,              brand: 'bmw',   slugFn: (m) => 'bmw-x' + m[1] },
  { rx: /\b(\d) ?series\b/i,       brand: 'bmw',   slugFn: (m) => 'bmw-' + m[1] + '-series' },
  { rx: /\b([1-8])(\d{2})i?\b/i,    brand: 'bmw',   slugFn: (m) => 'bmw-' + m[1] + '-series' },
  { rx: /\bi(\d)\b/i,              brand: 'bmw',   slugFn: (m) => 'bmw-i' + m[1] },
  { rx: /\b([2-5]008|[2-5]08)\b/i, brand: 'peugeot', slugFn: (m) => 'peugeot-' + m[1] },
  { rx: /\bk(\d)\b/i,              brand: 'kia',   slugFn: (m) => 'kia-k' + m[1] },
  { rx: /\bev(\d)\b/i,             brand: 'kia',   slugFn: (m) => 'kia-ev' + m[1] },
];

// === BRAND DETECTION ===
const BRAND_REGEX = {
  'kia': /\b(kia|ki a)\b/i,
  'mazda': /\b(mazda|maz da)\b/i,
  'peugeot': /\b(peugeot|pê giô|peugot|peugeout)\b/i,
  'bmw': /\b(bmw|b m w|bê em vê)\b/i,
  'mini': /\b(mini cooper|mini)\b/i
};

function detectBrand(text) {
  for (const [brand, rx] of Object.entries(BRAND_REGEX)) {
    if (rx.test(text)) return brand;
  }
  return '';
}

function detectModel(text, brand) {
  const t = text.toLowerCase();
  const sorted = Object.entries(MODEL_MAP).sort((a, b) => b[0].length - a[0].length);
  for (const [name, slug] of sorted) {
    const escaped = name.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    const rx = new RegExp('(?:^|[\\s,\\.!?\'"()])' + escaped + '(?:[\\s,\\.!?\'"()]|$)', 'i');
    if (rx.test(' ' + t + ' ')) {
      const inferredBrand = brand || slug.split('-')[0];
      if (VALID_SLUGS.size === 0 || VALID_SLUGS.has(slug)) {
        return { model_slug: slug, brand: inferredBrand };
      } else {
        console.log('[KEYWORD_ROUTER] Slug NOT in catalog:', slug);
        return { model_slug: '', brand: inferredBrand };
      }
    }
  }
  for (const pat of BRAND_PATTERNS) {
    const m = t.match(pat.rx);
    if (m) {
      const inferredBrand = brand || pat.brand;
      if (brand && brand !== pat.brand) continue;
      const slug = pat.slugFn(m);
      if (VALID_SLUGS.size === 0 || VALID_SLUGS.has(slug)) {
        return { model_slug: slug, brand: pat.brand };
      } else {
        console.log('[KEYWORD_ROUTER] Pattern slug NOT in catalog:', slug);
        return { model_slug: '', brand: pat.brand };
      }
    }
  }
  return { model_slug: '', brand };
}

// =============================================
// 1. PROFANITY → bắt buộc SAFETY_GUARD
// =============================================
const PROFANITY_LIST = [
  'đ[ếeê*._x]{0,2}o', 'đ[ụu*._]{0,2} ?m[ẹe]', 'đ[ấa*._]{0,2}t ?m[ẹe]?',
  'v[ãa]i ?(l[ồo]n|c[ặa]c)', 'đ[ồo] ?ngu', 'm[ẹe] ?m[àa]y',
  'con ?(chó|đ[ĩi])', 'ngu ?(v[ãa]i|thế)', 'khốn ?nạn', 'mất ?dạy',
  'cục ?phân', 'ngu ?s[ĩi]', 'óc ?ch[oó]',
  'f[uư*]c?k', 'shit', 'damn', 'bitch',
  'đm', 'dm', 'đkm', 'cc', 'clgt', 'vcl', 'wtf',
];
const PROFANITY_REGEX = new RegExp('(^|\\s)(' + PROFANITY_LIST.join('|') + ')(\\s|$|[.,!?])', 'i');
let _safety_guard = PROFANITY_REGEX.test(msg);

// =============================================
// 2. ENTITY EXTRACTION
// =============================================
let brand = detectBrand(msg);
const modelResult = detectModel(msg, brand);
if (modelResult.brand && !brand) brand = modelResult.brand;
const model_slug_raw = modelResult.model_slug;

// ALL-NEW UPGRADE
let model_slug = model_slug_raw;
const IS_NEW_INTENT = /\b(đời mới|mới nhất|all[- ]?new|thế hệ mới|phiên bản mới|version mới|new model|facelift|nâng cấp)\b/i.test(msg);
if (IS_NEW_INTENT && model_slug_raw) {
  const allNewSlug = model_slug_raw + '-all-new';
  if (VALID_SLUGS.has(allNewSlug)) {
    model_slug = allNewSlug;
    console.log('[KEYWORD_ROUTER] Upgraded to all-new:', allNewSlug);
  }
}

// Compare detection
let compare_target = '';
let compare_with_brand = '';
let compare_with_model = '';
if (/\b(so sánh|vs|với|và|hay)\b/i.test(msg) && model_slug) {
  const remaining = msg.replace(new RegExp(model_slug.split('-').pop(), 'i'), '');
  const secondResult = detectModel(remaining, '');
  if (secondResult.model_slug && secondResult.model_slug !== model_slug) {
    const THACO_BRANDS = ['kia', 'mazda', 'peugeot', 'bmw', 'mini'];
    const secondBrand = secondResult.model_slug.split('-')[0];
    if (THACO_BRANDS.includes(secondBrand)) compare_target = secondResult.model_slug;
    else { compare_with_brand = secondBrand; compare_with_model = secondResult.model_slug; }
  }
  const extMatch = msg.match(/\b(toyota|honda|hyundai|ford|vinfast|nissan|mitsubishi|mg|chevrolet|suzuki|volvo|mercedes|audi|lexus)\b/i);
  if (extMatch && !compare_with_brand) {
    compare_with_brand = extMatch[1].toLowerCase();
    const afterBrand = msg.substring(msg.toLowerCase().indexOf(compare_with_brand) + compare_with_brand.length).trim();
    const mw = afterBrand.match(/^\s*([A-Za-z0-9\-]+)/);
    if (mw) compare_with_model = mw[1];
  }
}

let car_type = '';
if (/\b(suv|gầm cao|xe gầm cao)\b/i.test(msg)) car_type = 'suv';
else if (/\b(sedan)\b/i.test(msg)) car_type = 'sedan';
else if (/\b(hatchback|hatch)\b/i.test(msg)) car_type = 'hatchback';

let seat_min = null;
const seatMatch = msg.match(/\b(\d+)\s*chỗ/);
if (seatMatch) seat_min = parseInt(seatMatch[1]);

let fuel = '';
if (/\b(máy dầu|diesel|dầu)\b/i.test(msg)) fuel = 'dầu';
else if (/\b(hybrid|lai điện)\b/i.test(msg)) fuel = 'hybrid';
else if (/\b(điện|ev|electric)\b/i.test(msg)) fuel = 'ev';
else if (/\b(xăng|petrol)\b/i.test(msg)) fuel = 'xăng';

let budget_max = null;
const xxMatch = msg.match(/(dưới|khoảng|tầm|budget|ngân sách|trong|từ)?\s*(\d)xx\s*(tỷ|tỉ|triệu|tr)?/i);
const budgetMatch = msg.match(/(dưới|khoảng|tầm|budget|ngân sách|trong|từ)?\s*(\d+(?:[.,]\d+)?)\s*(tỷ|tỉ|triệu|tr)/i);
if (xxMatch) {
  let num = parseInt(xxMatch[2]) * 100 * 1000000;
  if (xxMatch[3] && /tỷ|tỉ/i.test(xxMatch[3])) num = parseInt(xxMatch[2]) * 100 * 1000000000;
  if (/tầm|khoảng/i.test(xxMatch[1] || '')) num *= 1.1;
  budget_max = Math.round(num);
} else if (budgetMatch) {
  let num = parseFloat(budgetMatch[2].replace(',', '.'));
  const unit = budgetMatch[3].toLowerCase();
  if (unit === 'tỷ' || unit === 'tỉ') num *= 1000000000;
  else num *= 1000000;
  if (/tầm|khoảng/i.test(budgetMatch[1] || '')) num *= 1.1;
  budget_max = Math.round(num);
}

let price_sort = null;
if (/\b(rẻ nhất|thấp nhất|rẻ|giá thấp)\b/i.test(msg)) price_sort = 'asc';
else if (/\b(đắt nhất|mắc nhất|cao nhất|giá cao)\b/i.test(msg)) price_sort = 'desc';

// =============================================
// 3. BUILD OUTPUT
// =============================================
const pre = {
  category: _safety_guard ? 'SAFETY_GUARD' : '',
  sales_subcategory: '',
  brand: brand || '', model_slug: model_slug || '',
  car_type, seat_min, fuel, budget_max,
  use_case: null, qa_intents: [],
  compare_with_brand, compare_with_model, compare_target,
  price_sort, status: true
};

console.log('[KEYWORD_ROUTER] safety:', _safety_guard, '| brand:', brand, '| model:', model_slug);

return [{ json: {
  ...d,
  _pre_extracted: pre,
  _safety_guard: _safety_guard,
  _conflict_signals: []
}}];

// capture_reply — thêm logic INJECT ảnh xe vào đầu reply
// (chỉ khi khách đang hỏi sâu 1 xe — mode detail/compare_segment/close_deal)
const item = $input.first().json;
let reply = item.output || item.text || item.response || '';
const base = 'https://raw.githubusercontent.com/Meeyana/thacoauto-lib/main/';

function safe(fn, def = null) {
  try { return fn(); } catch (e) { return def; }
}

// Lấy model_slug + mode từ các node logic upstream (chỉ chạy nếu thật sự đi qua sales_lead branch)
const router = safe(() => $('xu_ly_category').first().json) || {};
const salesCtx = safe(() => $('Code in JavaScript').first().json) || {};
const mode = salesCtx.mode || '';
const brand = (router.brand || '').toLowerCase().trim();
const modelSlug = (router.model_slug || '').toLowerCase().trim();

// === IMAGE GATE 1: chỉ render khi KHÁCH HỎI CHI TIẾT XE LẦN ĐẦU ===
// Mode được phép: chỉ "detail" hoặc "detail_consultation" (= khách mới hỏi xe).
// KHÔNG render khi:
//   - detail_pricing_finance / detail_tech_specs / detail_close_deal (follow-up: hỏi giá/spec/lái thử)
//   - shortlist* / multi_quote / compare_external (nhiều xe / so đối thủ ngoài)
//   - các mode khác (showroom/complaint/static/...)
const introModes = ['detail', 'detail_consultation', 'compare_segment', 'compare_internal'];
const modeAllowsImage = modelSlug && introModes.includes(mode);

// === IMAGE GATE 2: chỉ render LẦN ĐẦU xuất hiện model trong session ===
// Nếu xe này đã được nói tới trong history → bỏ qua (tránh spam ảnh).
const _history = safe(() => $('parse_session').first().json._prev?.history) || [];
const _fullSlug = brand && !modelSlug.startsWith(brand + '-') ? `${brand}-${modelSlug}` : modelSlug;
const modelAlreadyShown = _history.some(h => {
  const hm = (h.model || '').toLowerCase();
  return hm && (hm === modelSlug || hm === _fullSlug);
});

const allowImage = modeAllowsImage && !modelAlreadyShown;

// Lấy image URL từ catalog (cache 1 lần / execution)
async function fetchModelImage(slug) {
  if (!slug) return null;
  try {
    const raw = await this.helpers.httpRequest({
      method: 'GET', url: base + 'wiki/models/catalog.json',
      json: true, returnFullResponse: false
    });
    const cat = (typeof raw === 'string' ? JSON.parse(raw) : raw).models || [];
    const fullSlug = slug.startsWith(brand + '-') || !brand ? slug : `${brand}-${slug}`;
    const m = cat.find(x => x.slug === fullSlug) || cat.find(x => x.slug === slug);
    return m ? { name: m.name, image: m.image } : null;
  } catch (e) { return null; }
}

let imageSuffix = '';
if (allowImage) {
  const hit = await fetchModelImage.call(this, modelSlug);
  if (hit && hit.image) {
    // Tránh duplicate: nếu reply text đã chứa URL ảnh này rồi → bỏ qua
    if (!reply.includes(hit.image)) {
      // Text TRƯỚC, ảnh SAU — append vào cuối reply
      imageSuffix = `\n\n![${hit.name}](${hit.image})`;
    }
  }
}

reply = reply + imageSuffix;

return [{
  json: {
    output: reply,
    _ai_reply_short: reply.slice(-300),
    _image_injected: !!imageSuffix,
    _image_skipped_reason: !modeAllowsImage ? `mode=${mode} not in introModes` : (modelAlreadyShown ? `model ${_fullSlug} already shown in history` : null)
  }
}];

const router = $input.first().json;
const trigger = $('When chat message received3').first().json;

// Lấy chatInput từ nhiều nguồn fallback
const userMsg =
  trigger.chatInput ||
  trigger.body?.message?.text ||                                    // Webhook raw
  $('Webhook').first().json?.body?.message?.text ||                 // nếu node tên khác
  '';

const sessionId = trigger.sessionId || trigger.body?.conversation?.id || 'default';
const prevHistory = ($('parse_session').first().json._prev?.history) || [];

const newTurn = {
  ts: new Date().toISOString(),
  user: userMsg.slice(0, 150),
  intent: router.category || '',
  subcat: router.sales_subcategory || '',
  mode: router.mode || '',
  qa_intents: Array.isArray(router.qa_intents) ? router.qa_intents : [],
  brand: router.brand || '',
  model: router.model_slug || ''
};

// Giữ 30 turn để abuse_guard có đủ data check 25msg/5min
const newHistory = [...prevHistory, newTurn].slice(-30);

return [{
  json: {
    ...router,
    sessionId,
    last_user_msg: newTurn.user,
    last_intent: newTurn.intent,
    last_brand: newTurn.brand,
    last_model: newTurn.model,
    history_json: JSON.stringify(newHistory)
  }
}];

// Static reply pool — random pick để tránh trả y hệt mỗi lần
const replies = [
  "Dạ em chỉ hỗ trợ tư vấn xe THACO AUTO (Kia, Mazda, Peugeot, BMW, MINI, xe tải/bus). Anh/Chị có câu hỏi nào về xe không ạ? Em hỗ trợ ngay!",

  "Dạ em là trợ lý tư vấn của THACO AUTO nên chỉ hỗ trợ các câu hỏi liên quan đến xe trong phạm vi của THACO AUTO thôi ạ. Em có thể giúp Anh/Chị: tìm xe phù hợp ngân sách, báo giá, tìm showroom gần nhất, hoặc tư vấn lái thử. Em sẵn sàng hỗ trợ ngay!",

  "Dạ chủ đề này hơi ngoài phạm vi hỗ trợ của em rồi ạ. Em chuyên về xe Kia/Mazda/Peugeot/BMW/MINI — Anh/Chị đang quan tâm dòng nào hoặc tầm giá khoảng bao nhiêu ạ?"
];

const pick = replies[Math.floor(Math.random() * replies.length)];
return [{ json: { output: pick } }];

// merge_lead_state — Code node sau "AI Agent — Test Drive Extractor"
// Parse JSON output → merge với state cũ → check completeness
// Bonus: nếu thiếu showroom + có user_location → geocode + suggest top 3 nearest

const aiRaw = $input.first().json.output || '';
const base = 'https://raw.githubusercontent.com/Meeyana/thacoauto-lib/main/';
const FALLBACK_URL = 'https://thacoautotphcm.vn/showrooms';
const MAX_DISTANCE_KM = 150;

// 1. Parse extractor JSON
let extracted = {};
try {
  const m = aiRaw.match(/\{[\s\S]*\}/);
  if (m) extracted = JSON.parse(m[0]);
} catch (e) {}

// 2. Load prior state TRỰC TIẾP từ row test_drives (cột vật lý: name/phone/model_interest/showroom/preferred_datetime)
let prior = {};
try {
  const row = $('d1_read_lead').first().json.data;
  if (row && row.sessionId) {
    prior = {
      name: row.name || null,
      phone: row.phone || null,
      model_interest: row.model_interest || null,
      showroom: row.showroom || null,
      preferred_datetime: row.preferred_datetime || null
    };
  }
} catch (e) {}

function isValidVnPhone(p) {
  if (!p) return false;
  const cleaned = p.toString().replace(/[\s\-\.]/g, '');
  return /^(\+84|84|0)[0-9]{9,10}$/.test(cleaned);
}

// Helper: APPEND model_interest (khách có thể quan tâm nhiều xe, không replace)
// Vd: prior="Sportage", new="K5" → "Sportage, K5"
// Dedupe case-insensitive để tránh "sportage, Sportage".
function mergeModels(newVal, oldVal) {
  const normalize = s => (s || '').toString().trim();
  const oldStr = normalize(oldVal);
  const newStr = normalize(newVal);
  if (!newStr) return oldStr || null;
  if (!oldStr) return newStr;
  const oldList = oldStr.split(/\s*,\s*/).map(s => s.trim()).filter(Boolean);
  const oldLower = oldList.map(s => s.toLowerCase());
  // Tách newStr nếu extractor trả nhiều xe trong 1 chuỗi
  const newList = newStr.split(/\s*,\s*/).map(s => s.trim()).filter(Boolean);
  for (const n of newList) {
    if (!oldLower.includes(n.toLowerCase())) {
      oldList.push(n);
      oldLower.push(n.toLowerCase());
    }
  }
  return oldList.join(', ');
}

// 3. Merge
const merged = {
  name: extracted.name || prior.name || null,
  phone: extracted.phone || prior.phone || null,
  // ⭐ APPEND thay vì replace — khách quan tâm nhiều xe sẽ tích lũy
  model_interest: mergeModels(extracted.model_interest, prior.model_interest),
  showroom: extracted.showroom || prior.showroom || null,
  preferred_datetime: extracted.preferred_datetime || prior.preferred_datetime || null
};

// user_location KHÔNG persist (chỉ dùng để gợi ý showroom turn này)
const user_location = (extracted.user_location || '').trim();

if (merged.phone && !isValidVnPhone(merged.phone)) {
  merged.phone = null;
}

const missing = Object.entries(merged)
  .filter(([k, v]) => !v)
  .map(([k]) => k);
const isComplete = missing.length === 0;

// LEAD POLICY: chỉ cần CÓ PHONE là đã đủ để Sales gọi (lead-able).
// Các field còn thiếu sẽ được cập nhật ở turn sau qua appendOrUpdate trên sessionId.
const isLeadable = !!merged.phone;
const completionStatus = isComplete ? 'complete' : (isLeadable ? 'partial' : 'incomplete');

const sessionId = $('When chat message received3').item.json.sessionId || 'default';

// =========================================================
// BONUS: nếu thiếu showroom + có user_location → suggest
// =========================================================
let showroom_suggestions = [];
let suggestion_text = '';

function inferBrandFromModel(modelText) {
  const t = (modelText || '').toLowerCase();
  if (/\b(sportage|carnival|carens|seltos|sorento|sonet|k3|k5|morning|new\s*carnival)\b/.test(t)) return 'kia';
  if (/\b(mazda|cx-?\d+|mx-?\d+|cx5|cx3|cx30|cx8|mazda3|mazda6|mazda2)\b/.test(t)) return 'mazda';
  if (/\b(peugeot|3008|5008|2008|408|traveller)\b/.test(t)) return 'peugeot';
  if (/\b(bmw|x[1-7]\b|series|3 ?series|5 ?series|7 ?series|i[345789]\b|330|320|520|530|730)\b/.test(t)) return 'bmw';
  if (/\b(mini|cooper|countryman|clubman)\b/.test(t)) return 'mini';
  return '';
}

function haversineKm(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const toRad = x => x * Math.PI / 180;
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a = Math.sin(dLat/2)**2 +
            Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLon/2)**2;
  return 2 * R * Math.asin(Math.sqrt(a));
}


const PASSENGER_BRANDS = ['kia', 'mazda', 'peugeot', 'bmw', 'mini'];
function brandMatches(showroom, b) {
  if (!b) return true;
  const slugs = showroom.brand_slugs || [];
  // Exact match — KHÔNG dùng includes() vì 'kia-frontier'.includes('kia') sẽ kéo nhầm xe tải
  if (!slugs.includes(b)) return false;
  // Brand xe du lịch → chỉ lấy showroom oto, loại tai/bus
  if (PASSENGER_BRANDS.includes(b) && showroom.type_showroom && showroom.type_showroom !== 'oto') return false;
  return true;
}

if (!merged.showroom && user_location) {
  try {
    // Geocode user location
    const geo = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://nominatim.openstreetmap.org/search',
      qs: { format: 'json', q: /vietnam|việt nam/i.test(user_location) ? user_location : (user_location + ', Việt Nam'), limit: 1 },
      headers: { 'User-Agent': 'thacoauto-chatbot/1.0 (contact: phogotarot@gmail.com)' },
      json: true,
      returnFullResponse: false
    });
    const arr = (typeof geo === 'string') ? JSON.parse(geo) : geo;

    if (Array.isArray(arr) && arr.length) {
      const ulat = parseFloat(arr[0].lat);
      const ulon = parseFloat(arr[0].lon);

      // Load catalog
      const cat = await this.helpers.httpRequest({
        method: 'GET',
        url: base + 'wiki/dealers/catalog.json',
        json: true,
        returnFullResponse: false
      });
      const data = (typeof cat === 'string') ? JSON.parse(cat) : cat;

      // Filter brand từ model_interest
      const inferredBrand = inferBrandFromModel(merged.model_interest || '');
      let candidates = (data.showrooms || []).filter(s =>
        typeof s.lat === 'number' && typeof s.lon === 'number'
      );
      if (inferredBrand) {
        const filtered = candidates.filter(s => brandMatches(s, inferredBrand));
        if (filtered.length) candidates = filtered;
      }

      const ranked = candidates
        .map(s => ({
          title: s.title,
          brand: (s.brands || []).join(', '),
          ward: s.address?.ward || '',
          street: s.address?.street || '',
          phone: s.phone_sale || '—',
          distance_km: haversineKm(ulat, ulon, s.lat, s.lon)
        }))
        .sort((a, b) => a.distance_km - b.distance_km)
        .slice(0, 3);

      if (ranked.length && ranked[0].distance_km > MAX_DISTANCE_KM) {
        // Quá xa → không gợi ý, báo cho AI biết
        showroom_suggestions = [];
        suggestion_text = `[KHÔNG có showroom phù hợp gần "${user_location}" — gần nhất cũng cách ~${ranked[0].distance_km.toFixed(0)}km. Dữ liệu hiện chỉ phủ cụm HCM và lân cận. Gợi ý cho AI: xin lỗi khách, KHÔNG ép khách chọn showroom xa, mời khách xem danh sách toàn quốc tại ${FALLBACK_URL} hoặc gọi 1900 545 591 để chuyên viên tư vấn showroom gần khách.]`;
      } else {
        showroom_suggestions = ranked;
        if (ranked.length) {
          suggestion_text = `Top ${ranked.length} showroom${inferredBrand ? ' ' + inferredBrand.toUpperCase() : ''} gần "${user_location}":\n` +
            ranked.map((s, i) => `  ${i+1}. ${s.title} — cách ~${s.distance_km.toFixed(1)}km — ${s.street}, P.${s.ward} — ${s.phone}`).join('\n');
        }
      }
    }
  } catch (e) {
    suggestion_text = `[Không truy vấn được showroom gần nhất: ${e.message}. Có thể gửi URL tra cứu: ${FALLBACK_URL}]`;
  }
}

return [{
  json: {
    sessionId,
    lead_data: merged,
    lead_partial_json: JSON.stringify(merged),
    missing_fields: missing,
    is_complete: isComplete,
    is_leadable: isLeadable,
    completion_status: completionStatus,
    user_location,
    showroom_suggestions,
    suggestion_text,
    fallback_url: FALLBACK_URL,
    _debug_extracted: extracted,
    _debug_prior: prior
  }
}];

// reply_complete — Code node sau "gs_append_test_drive"
// Static reply xác nhận đã save lead — KHÔNG gọi AI để tiết kiệm token + đảm bảo format ổn định.

const d = $('merge_lead_state').first().json.lead_data;

const reply = `Dạ em đã ghi nhận đăng ký lái thử của Anh/Chị ạ ✅

📋 **Thông tin đã lưu:**
- Họ tên: ${d.name}
- SĐT: ${d.phone}
- Xe quan tâm: ${d.model_interest}
- Showroom: ${d.showroom}
- Thời gian: ${d.preferred_datetime}

🚗 Chuyên viên Sale sẽ liên hệ Anh/Chị trong **1-2 giờ làm việc** để xác nhận lịch và chuẩn bị xe.

Cảm ơn Anh/Chị đã quan tâm THACO AUTO!

📞 Hotline hỗ trợ: **1900 545 591**`;

return [{ json: { output: reply } }];

