} 
else if (userMsg.match(/(bạn là ai|mày là ai|là bot|bot à|ai tư vấn|tên gì)/)) {
  reply = pickRandom(replyPool.identity);
} 
else {
  reply = pickRandom(replyPool.hello); // Nếu không có từ khóa trên thì lấy mặc định là lời chào
}

// Trả kết quả ra luồng
return [{ json: { output: reply } }];

