// Helper truy cập node có thể không chạy trong run hiện tại (mỗi category đi 1 nhánh)
function safe(fn, def = null) {
  try { return fn(); } catch (e) { return def; }
}

const trigger = $('When chat message received3').first().json;
const router  = $('xu_ly_category').first().json;
const reply   = $('capture_reply').first().json.output || '';

// Tìm node "logic" đã chạy trong run này — duyệt theo thứ tự ưu tiên
const candidates = [
  'Code in JavaScript',          // SALES_LEAD (split via Route by Sales Mode → 5 reply sub-nodes)
  'merge_lead_state',            // SALES_LEAD close_deal (lái thử)
  'Code in Javescript 1',        // NETWORK_LOCATION (showroom)
  'trade_in_code',               // TRADE_IN
  'brand_info_logic',            // BRAND_INFO
  'recruitment_code',            // RECRUITMENT
  'urgent_consult_code',         // URGENT_CONSULT
  'company_contact_code'         // COMPANY_CONTACT
];

let logic_node = null, mode = null, files_used = [], bundle_size = 0, context_bundle = '';
for (const name of candidates) {
  const out = safe(() => $(name).first().json);
  if (out && (out.mode || out.context_bundle || out.files_used)) {
    logic_node     = name;
    mode           = out.mode || null;
    files_used     = out.files_used || [];
    bundle_size    = out.bundle_size || (out.context_bundle ? out.context_bundle.length : 0);
    context_bundle = out.context_bundle || '';
    break;
  }
}

// Nhánh static (greeting/safety_guard/complaint/out_of_scope/disambiguator/reply_complete) → không có context
if (!logic_node) {
  const staticCandidates = ['reply_greeting','safety_guard_reply','complaint_reply','reply_out_of_scope','reply_complete','AI Agent — Disambiguator'];
  for (const name of staticCandidates) {
    if (safe(() => $(name).first().json)) { logic_node = name; mode = 'static'; break; }
  }
}

// =========================================================
// TOKEN USAGE TRACKING — gom token + cost từ mọi AI Agent đã chạy
// =========================================================
// Pricing Gemini (USD per 1M tokens) — cập nhật khi đổi model.
// Default: gemini-2.0-flash (rẻ + đủ dùng). Sửa nếu workflow đổi model.
const PRICING = {
  'gemini-2.5-pro':       { in: 1.25,  out: 10.00 },
  'gemini-2.5-flash':     { in: 0.30,  out: 2.50 },
  'gemini-2.0-flash':     { in: 0.10,  out: 0.40 },
  'gemini-1.5-pro':       { in: 1.25,  out: 5.00 },
  'gemini-1.5-flash':     { in: 0.075, out: 0.30 },
  'default':              { in: 0.10,  out: 0.40 }  // fallback = 2.0-flash
};
const DEFAULT_MODEL = 'gemini-2.0-flash';

// Mọi node AI agent có thể chạy trong run này, kèm LLM sub-node tương ứng
// (n8n thường expose token usage trên LLM sub-node, KHÔNG phải agent)
const AGENT_LLM_MAP = {
  'AI Agent':                          'Google Gemini Chat Model',   // classifier
  'AI Agent - Location Extractor':     'Google Gemini Chat Model2',  // location
  'Message a model':                   'Google Gemini Chat Model3',  // showroom reply
  'reply_single_car':                  'Google Gemini Chat Model1',  // sales_lead detail/compare_internal/compare_segment/close_deal
  'reply_pricing':                     'Gemini_pricing',             // sales_lead pricing_finance
  'reply_tech_specs':                  'Gemini_tech_specs',          // sales_lead tech_specs
  'reply_compare_external':            'Gemini_compare_external',    // sales_lead compare_external
  'reply_shortlist':                   'Gemini_shortlist',           // sales_lead shortlist/multi_quote/ask_more
  'AI Agent — Disambiguator':          'Google Gemini Chat Model4',  // ambiguous
  'AI Agent - Test Drive Extractor':   'Google Gemini Chat Model5',  // close_deal extract
  'AI Agent - reply_ask_missing':      'Google Gemini Chat Model6',  // close_deal ask
  'AI Agent-Hand off reply':           'Google Gemini Chat Model7'   // handoff
};

// System prompt overhead per agent (chars) — đo tay từ system prompts thực tế.
// Sau refactor split sub-nodes: mỗi reply node ngắn hơn nhiều so với Message a model1 cũ (~6800).
const SYS_OVERHEAD = {
  'AI Agent':                          4800,  // classifier prompt dài
  'AI Agent - Location Extractor':     2400,
  'Message a model':                   3700,
  'reply_single_car':                  3200,  // detail / compare_internal / compare_segment / close_deal
  'reply_pricing':                     2200,  // pricing_finance (LIST_ONLY/SUMMARY/DETAILED)
  'reply_tech_specs':                  1400,  // tech_specs với emoji bullets
  'reply_compare_external':            900,   // compare_external fixed format
  'reply_shortlist':                   1700,  // shortlist/multi_quote/ask_more
  'AI Agent — Disambiguator':          1500,
  'AI Agent - Test Drive Extractor':   1700,
  'AI Agent - reply_ask_missing':      2100,
  'AI Agent-Hand off reply':           3500
};

// Thử lấy token THẬT — duyệt nhiều path trên cả agent + LLM sub-node
function extractTokens(agentName) {
  // Path A: thử trên agent node trước
  const candidates = [agentName, AGENT_LLM_MAP[agentName]].filter(Boolean);
  for (const nodeName of candidates) {
    // Lấy tất cả items vì LLM sub-node có thể chạy nhiều lần (tool-calling agents)
    const items = safe(() => $(nodeName).all()) || [];
    let sumIn = 0, sumOut = 0, found = false;
    for (const item of items) {
      const j = item?.json;
      if (!j) continue;
      // Try multiple shapes
      const tu = j.tokenUsage || j.usage;
      const meta = j?.response?.usageMetadata || j?.usageMetadata
                || j?.response?.response_metadata?.usage_metadata
                || j?.generations?.[0]?.[0]?.generationInfo?.usageMetadata;
      if (tu) {
        const i = Number(tu.promptTokens || tu.input_tokens || tu.prompt_tokens || tu.input || tu.promptTokenCount || 0);
        const o = Number(tu.completionTokens || tu.output_tokens || tu.completion_tokens || tu.output || tu.candidatesTokenCount || 0);
        if (i > 0 || o > 0) { sumIn += i; sumOut += o; found = true; }
      }
      if (meta) {
        const i = Number(meta.promptTokenCount || meta.input_tokens || 0);
        const o = Number(meta.candidatesTokenCount || meta.output_tokens || meta.outputTokenCount || 0);
        if (i > 0 || o > 0) { sumIn += i; sumOut += o; found = true; }
      }
    }
    if (found) return { in: sumIn, out: sumOut };
  }
  return null;
}

// Estimate token theo char count + per-agent overhead. Tiếng Việt dense hơn English
// → CHARS_PER_TOKEN ~1.8 (đo từ thực tế Gemini với prompt VN+EN hỗn hợp).
const CHARS_PER_TOKEN = 1.8;
function estimateTokens(agentName) {
  const json = safe(() => $(agentName).first().json);
  if (!json) return null;
  const outText = (json.output || json.text || json.response || '').toString();
  // Input = system prompt overhead + user msg + bundle (cho reply agents)
  // Các extractor (Location/TestDrive) dùng ít context hơn — overhead nhỏ hơn
  const isReplyAgent = /Message a model|reply_single_car|reply_pricing|reply_tech_specs|reply_compare_external|reply_shortlist|reply_ask_missing|Hand off|Disambiguator/i.test(agentName);
  const ctxText = isReplyAgent ? (context_bundle || '') : '';
  const userText = (trigger.chatInput || '').toString();
  const sysOverhead = SYS_OVERHEAD[agentName] || 2500;
  const inputChars = userText.length + ctxText.length + sysOverhead;
  return {
    in:  Math.round(inputChars / CHARS_PER_TOKEN),
    out: Math.round(outText.length / CHARS_PER_TOKEN)
  };
}

const AI_AGENTS = Object.keys(AGENT_LLM_MAP);
let totalIn = 0, totalOut = 0;
const modelsUsed = new Set();
let tokenSource = 'estimated';
let realCount = 0, estCount = 0;
const _agentBreakdown = []; // debug: token mỗi agent

for (const agent of AI_AGENTS) {
  if (!safe(() => $(agent).first().json)) continue;
  const real = extractTokens(agent);
  let used, src;
  if (real && (real.in > 0 || real.out > 0)) {
    used = real; src = 'real'; realCount++;
  } else {
    used = estimateTokens(agent) || { in: 0, out: 0 }; src = 'est'; estCount++;
  }
  totalIn  += used.in;
  totalOut += used.out;
  modelsUsed.add(DEFAULT_MODEL);
  _agentBreakdown.push({ agent, src, in: used.in, out: used.out });
}
if (realCount > 0 && estCount === 0) tokenSource = 'real';
