}

// Tách ảnh từ MARKDOWN GỐC: ![alt](url) hoặc URL trần kết thúc bằng .png/.jpg/.jpeg/.gif/.webp
const imgRegex = /!\[[^\]]*\]\((https?:\/\/[^\s)]+\.(?:png|jpe?g|gif|webp))\)|(?<!\()(https?:\/\/[^\s)]+\.(?:png|jpe?g|gif|webp))/gi;
const images = [];
let m;
while ((m = imgRegex.exec(rawForImages)) !== null) {
  const url = m[1] || m[2];
  if (url && !images.includes(url)) images.push(url);
}

// Text gửi đi = bản đã strip markdown
