for (const u of images) {
  textOnly = textOnly.split(u).join('');
}
textOnly = textOnly.replace(/\n{3,}/g, '\n\n').trim();

function mimeOf(url) {
  const ext = url.split('?')[0].split('.').pop().toLowerCase();
  return ({
    png: 'image/png',
    jpg: 'image/jpeg',
    jpeg: 'image/jpeg',
    gif: 'image/gif',
    webp: 'image/webp'
  })[ext] || 'image/png';
}

// Build Subiz messages — 1 message text + attachments (tất cả ảnh gộp 1 lần)
