function stripMd(s) {
  if (!s) return '';
  let t = s;

  // 1. Code fence ```...``` → giữ nội dung, bỏ fence
  t = t.replace(/```[a-zA-Z]*\n?([\s\S]*?)```/g, '$1');

  // 2. Inline code `x` → x
  t = t.replace(/`([^`]+)`/g, '$1');

  // 3. Image ![alt](url) → BỎ (đã tách thành attachments ở format_subiz_response)
  t = t.replace(/!\[[^\]]*\]\([^)]+\)/g, '');

  // 4. Link [text](url) → "text: url"
  t = t.replace(/\[([^\]]+)\]\((https?:\/\/[^)]+)\)/g, '$1: $2');

  // 5. Headers # / ## / ### → bỏ # đầu dòng
  t = t.replace(/^\s*#{1,6}\s+/gm, '');

  // 6. Bold/italic — XỬ LÝ THEO THỨ TỰ DÀI → NGẮN
  t = t.replace(/\*\*\*([^*]+)\*\*\*/g, '$1');
  t = t.replace(/___([^_]+)___/g, '$1');
  t = t.replace(/\*\*([^*]+)\*\*/g, '$1');
  t = t.replace(/__([^_]+)__/g, '$1');
  t = t.replace(/(^|[\s(])\*([^*\s][^*]*?)\*(?=[\s.,!?)]|$)/g, '$1$2');
  t = t.replace(/(^|[\s(])_([^_\s][^_]*?)_(?=[\s.,!?)]|$)/g, '$1$2');

  // 7. Strikethrough ~~x~~ → x
  t = t.replace(/~~([^~]+)~~/g, '$1');

  // 8. Bullet - / * / + ở đầu dòng → •
  t = t.replace(/^[\s]*[-*+]\s+/gm, '• ');

  // 9. Blockquote > → bỏ
  t = t.replace(/^\s*>\s?/gm, '');

  // 10. Horizontal rule (--- *** ___) → bỏ
  t = t.replace(/^[\s]*([-*_])\1{2,}[\s]*$/gm, '');

  // 11. Wikilink [[...]] → bỏ ngoặc
  t = t.replace(/\[\[([^\]]+)\]\]/g, '$1');

  // 12. Dọn dẹp: tối đa 2 newline liên tiếp, trim
  t = t.replace(/\n{3,}/g, '\n\n').trim();

  return t;
}

