        bundle = '[DANH SÁCH XE ' + brand.toUpperCase() + ']\n' + models.map(m => '- ' + m.name + ' (' + m.slug + '): ' + (m.price_range || '')).join('\n');
      } catch(e) { bundle = '[Brand: ' + brand + ']'; }

    // ==============================
    // NETWORK_LOCATION — full dealer lookup (replicate Code in Javescript 1)
    // ==============================
    } else if (cat === 'NETWORK_LOCATION') {
      const dealerBrand = brand || shared.brand || '';
