          .map(s => ({ s, score: scoreMatch(s.title, showroomName) }))
          .filter(x => x.score > 0).sort((a,b) => b.score - a.score);
        let matches = scored.length ? scored.filter(x => x.score === scored[0].score).map(x => x.s) : [];
        if (dealerBrand && matches.length > 1) matches = matches.filter(s => brandMatches(s, dealerBrand)) || matches;

