            '- Website: ' + (f.website||'—');
        } else {
          bundle = '=== KHU VỰC: ' + showroomName.toUpperCase() + ' (' + matches.length + ' showroom) ===\n' +
            matches.map(s => '- ' + s.title + ' | ' + s.brands.join(', ') + ' | ' + (s.phone_sale||'—') + ' | Maps: ' + (s.map_url||'—')).join('\n');
        }

      } else if (userLoc) {
