          bundle = '[SHOWROOM GẦN NHẤT] Không xác định được vị trí "' + userLoc + '". URL tra cứu: ' + FALLBACK_URL + ' | Hotline: 1900 545 591';
        } else {
          let candidates = (dealerData.showrooms || []).filter(s => typeof s.lat==='number' && typeof s.lon==='number');
          if (dealerBrand) candidates = candidates.filter(s => brandMatches(s, dealerBrand));
          const ranked = candidates.map(s => ({ ...s, distance_km: haversineKm(coords.lat, coords.lon, s.lat, s.lon) }))
            .sort((a,b) => a.distance_km - b.distance_km);
          const inRange = ranked.filter(s => s.distance_km <= MAX_DISTANCE_KM).slice(0, 3);

          if (!inRange.length) {
            bundle = '[SHOWROOM] Khu vực "' + userLoc + '" chưa có showroom' + (dealerBrand ? ' ' + dealerBrand.toUpperCase() : '') + ' trong phạm vi ' + MAX_DISTANCE_KM + 'km.\n' +
              'URL tra cứu toàn quốc: ' + FALLBACK_URL + ' | Hotline: 1900 545 591';
          } else {
            const brandLabel = dealerBrand ? dealerBrand.toUpperCase() : 'THACO AUTO';
            bundle = '=== SHOWROOM ' + brandLabel + ' GẦN NHẤT TỪ "' + userLoc + '" ===\n' +
              'Toạ độ: ' + coords.lat.toFixed(5) + ', ' + coords.lon.toFixed(5) + '\n\n' +
              inRange.map((s,j) => (j+1) + '. ' + s.title + ' — cách ~' + s.distance_km.toFixed(1) + ' km\n' +
                '   Địa chỉ: ' + s.address.full + '\n' +
                '   Bán hàng: ' + (s.phone_sale||'—') + ' | Dịch vụ: ' + (s.phone_service||'—') + '\n' +
                '   Maps: ' + (s.map_url||'—')).join('\n\n');
          }
        }

      } else if (province) {
        // Province link
        const provUrl = (dealerData.province_urls || {})[province] || null;
        if (provUrl) {
          bundle = '=== SHOWROOM TẠI ' + province.toUpperCase() + ' ===\nURL chính thức: ' + provUrl + '\nBrand quan tâm: ' + (dealerBrand || 'tất cả');
        } else {
          bundle = '[SHOWROOM] Chưa có URL riêng cho tỉnh "' + province + '". URL tra cứu: ' + FALLBACK_URL + ' | Hotline: 1900 545 591';
        }

      } else {
        // Chưa biết khu vực → hỏi + cung cấp fallback URL
        bundle = '[SHOWROOM] Khách hỏi showroom nhưng chưa nói khu vực cụ thể.\n' +
          'Hướng dẫn: hỏi khách ở tỉnh/thành nào, hoặc gửi URL tra cứu: ' + FALLBACK_URL + '\n' +
          'Hotline hỗ trợ: 1900 545 591';
      }

    // ==============================
    // SERVICE_APPOINTMENT
    // ==============================
    } else if (cat === 'SERVICE_APPOINTMENT') {
      bundle = '[DỊCH VỤ BẢO DƯỠNG]\n' +
        'Quý khách đặt lịch bảo dưỡng/sửa chữa qua:\n' +
        '1. Ứng dụng THACO AUTO Services (iOS/Android)\n' +
        '2. Hotline: 1900 636 247\n' +
        '3. Liên hệ trực tiếp showroom gần nhất';

    } else if (cat === 'TRADE_IN') {
      try {
        const ti = await this.helpers.httpRequest({ method:'GET', url: base + 'wiki/services/trade-in.md' });
        bundle = '[THU CŨ ĐỔI MỚI]\n' + ti.substring(0, 1500);
      } catch(e) { bundle = '[TRADE-IN] Chương trình Thu cũ Đổi mới — liên hệ showroom gần nhất hoặc hotline 1900 636 247.'; }

    } else if (cat === 'GREETING') {
      bundle = '[CHÀO HỎI]';

    } else if (cat === 'CUSTOMER_SERVICE') {
      bundle = '[CHĂM SÓC KHÁCH HÀNG]\nGhi nhận thắc mắc. Vui lòng cung cấp thêm chi tiết (showroom mua xe, thời gian, mã đơn) để hỗ trợ nhanh.\nHotline CSKH: 1900 636 247';

    } else if (cat === 'POLICY_LEGAL') {
      bundle = '[CHÍNH SÁCH]\nThông tin bảo hành chính hãng, trả góp, thủ tục đăng ký — liên hệ showroom hoặc hotline 1900 636 247.';

    } else if (cat === 'COMPANY_CONTACT') {
      bundle = '[LIÊN HỆ CÔNG TY]\nTHACO AUTO — Hotline: 1900 636 247\nWebsite: https://thacoauto.vn\nFanpage: https://facebook.com/thacoauto';

    } else {
      bundle = '[' + cat + '] Thông tin sẽ được cung cấp bởi nhân viên tư vấn. Hotline: 1900 636 247';
    }
  } catch(e) {
    bundle = '[' + cat + '] Lỗi fetch: ' + e.message + '. Hotline hỗ trợ: 1900 636 247';
  }

  bundles.push({
    id: 'i' + (i + 1),
    category: cat,
    sub: sub,
    slug: slug,
    brand: brand || shared.brand || '',
    context_bundle: bundle
  });
}

// Build synthesizer prompts
const bundleText = bundles.map((b, i) => {
  return '[BUNDLE ' + (i+1) + ' — ' + b.category + (b.sub ? '/' + b.sub : '') + (b.slug ? ' ' + b.slug : '') + ']\n' + b.context_bundle;
}).join('\n\n---\n\n');

const synthSystem = 'Bạn là tư vấn viên chuyên nghiệp THACO AUTO (Kia, Mazda, Peugeot, BMW, MINI).\n' +
  'Xưng "Em" - "Anh/Chị". Lịch sự, hữu ích, gọn gàng.\n\n' +
  'Khách hỏi câu KÉP gồm ' + bundles.length + ' ý.\n\n' +
  'QUY TẮC:\n' +
  '1. Đánh số (1), (2)... phân tách các vế\n' +
  '2. KHÔNG lặp xưng hô giữa các vế\n' +
  '3. Mỗi vế dùng ĐÚNG bundle dữ liệu tương ứng\n' +
  '4. KHÔNG bịa địa chỉ, hotline, link, khoảng cách — chỉ dùng data trong bundle\n' +
  '5. Nếu bundle showroom có URL → BẮT BUỘC đính kèm\n' +
  '6. Nếu bundle showroom thiếu info vị trí → hỏi khách ở khu vực nào\n' +
  '7. KHÔNG dùng markdown (**, ##, -, *)\n' +
  '8. Tối đa 300 từ\n\n' +
  'DỮ LIỆU:\n' + bundleText;

console.log('[BUILD_MULTI] intents:', bundles.length, '| categories:', bundles.map(b=>b.category).join('+'), '| bundle chars:', bundleText.length);

// === SESSION CONTEXT — giống các AI Agent khác ===
let turnCount = 0;
let lastUserMsg = '';
let lastAiReply = '';
let historyBlock = '';
let isFirstTurn = true;
try {
  const prev = $('parse_session').first().json._prev || {};
  const history = prev.history || [];
  turnCount = history.length;
  isFirstTurn = turnCount === 0;
  lastUserMsg = prev.last_user_msg || '';
  lastAiReply = prev.last_ai_reply || '';
  // Build history block (last 5 turns)
  const recentHistory = history.slice(-5);
  historyBlock = recentHistory.map(h => 
    '[' + (h.intent || '?') + '] Q: ' + (h.user_msg || '').substring(0, 80) + ' → A: ' + (h.ai_reply || '').substring(0, 80)
  ).join('\n');
} catch(e) {
  console.log('[BUILD_MULTI] parse_session not available:', e.message);
}

const turnStatus = isFirstTurn
  ? '👋 TURN ĐẦU — được phép chào hỏi 1 lần.'
  : '⚠️ TURN TIẾP THEO (#' + (turnCount + 1) + ') — TUYỆT ĐỐI KHÔNG chào lại.';

// Build user prompt (giống format của reply_pricing, Message a model, etc.)
const userPrompt = '### [TRẠNG THÁI HỘI THOẠI]\n' + turnStatus + '\n\n' +
  '### [TIN NHẮN KHÁCH]\n"' + chatInput + '"\n\n' +
  '### [NGỮ CẢNH TURN TRƯỚC]\n' +
  '- Câu hỏi gần nhất: "' + (lastUserMsg || '(chưa có)') + '"\n' +
  '- AI vừa trả lời: "' + (lastAiReply ? lastAiReply.substring(0, 200) : '(chưa có)') + '"\n\n' +
  '### [LỊCH SỬ 5 TURN GẦN NHẤT]\n' + (historyBlock || '(chưa có lịch sử)');

console.log('[BUILD_MULTI] turn:', turnCount, '| isFirst:', isFirstTurn, '| intents:', bundles.length);

return [{ json: {
  ...d,
  _synth_system_prompt: synthSystem,
  _synth_user_prompt: userPrompt,
  _bundles: bundles,
  _reply_mode: 'multi',
  _turn_count: turnCount,
  _is_first_turn: isFirstTurn,
  chatInput: chatInput
}}];
